from flask import Flask, request, jsonify
from flask_bcrypt import Bcrypt
from flask_jwt_extended import JWTManager
import datetime

app = Flask(__name__)
app.config["JWT_SECRET_KEY"] = "your-secret-key"
jwt = JWTManager(app)
bcrypt = Bcrypt(app)

users = {
    "user1": {"password": bcrypt.generate_password_hash("password1")},
    "user2": {"password": bcrypt.generate_password_hash("password2")},
}

@app.route("/login", methods=["POST"])
def login():
    username = request.json.get("username")
    password = request.json.get("password")
    if username in users and bcrypt.check_password_hash(users[username]["password"], password):
        token = jwt.encode({"user": username}, datetime.timedelta(minutes=30))
        return jsonify({"token": token})
    else:
        return jsonify({"error": "Invalid credentials"}), 401

@app.route("/protected", methods=["GET"])
@jwt.requires_auth
def protected():
    return jsonify({"message": "Protected endpoint accessed successfully."})

if __name__ == "__main__":
    app.run(debug=True)